import React, { useState } from "react";
import { empathicEcho } from "../services/ai";
import { addNote } from "../stores/notesStore";
import { Events, track } from "../analytics/track";

export const NoteWithEcho: React.FC = () => {
  const [text, setText] = useState("");
  const [echo, setEcho] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(false);

  const handleSave = async () => {
    const v = text.trim();
    if (!v) return;
    setLoading(true);
    try {
      const echoText = await empathicEcho(v);
      setEcho(echoText);
      addNote(v, echoText);
      track(Events.NoteSaved, {});
    } catch (e) {
      addNote(v);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="rounded-[12px] border border-neutral-200 bg-white p-3">
      <div className="mb-1.5 font-semibold">收藏備註（感受）</div>
      <textarea
        rows={3}
        placeholder="寫下這間帶給你的感覺…"
        value={text}
        onChange={(e) => setText(e.target.value)}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        className="w-full rounded-[8px] border border-neutral-200 p-2"
      />
      {focused && <div className="mt-1 text-xs text-neutral-500">慢慢寫，我在。</div>}
      <div className="mt-2 flex gap-2">
        <button onClick={handleSave} disabled={loading} className="rounded-[8px] border border-brand bg-brand px-3 py-2 text-white disabled:opacity-50">
          {loading ? "生成中…" : "存入便條（含回聲）"}
        </button>
        {echo && <span className="text-neutral-500">AI 回聲：{echo}</span>}
      </div>
    </div>
  );
};
