import React, { useState } from "react";
import { politeRewrite } from "../services/ai";
import { Events, track } from "../analytics/track";

export const PoliteRewrite: React.FC<{ onAdopt?: (text: string) => void }> = ({ onAdopt }) => {
  const [draft, setDraft] = useState("");
  const [audience, setAudience] = useState<"owner" | "agent">("agent");
  const [intent, setIntent] = useState<"view" | "detail" | "pet" | "price">("detail");
  const [v1, setV1] = useState<string | null>(null);
  const [v2, setV2] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [sent, setSent] = useState(false);

  const handleRewrite = async () => {
    const d = draft.trim();
    if (!d) return;
    setLoading(true);
    try {
      const out = await politeRewrite(d, { audience, intent });
      const m = out.split(/\n+/).map(s => s.trim()).filter(Boolean);
      const a = m.find(x => /^V1/.test(x)) || "";
      const b = m.find(x => /^V2/.test(x)) || "";
      setV1(a.replace(/^V1[:：]\s?/, ""));
      setV2(b.replace(/^V2[:：]\s?/, ""));
      track(Events.RewriteGen, { audience, intent });
    } finally {
      setLoading(false);
    }
  };

  const adopt = (text: string) => {
    onAdopt?.(text);
    setSent(true);
    track(Events.RewriteAdopt, { audience, intent });
    setTimeout(() => setSent(false), 2500);
  };

  return (
    <div className="rounded-[12px] border border-neutral-200 bg-white p-3">
      <div className="mb-1.5 font-semibold">禮貌改寫小幫手</div>
      <div className="mb-2 flex flex-wrap gap-2">
        <label>對象
          <select value={audience} onChange={e => setAudience(e.target.value as any)} className="ml-1.5 rounded-[8px] border border-neutral-200 p-1.5">
            <option value="agent">仲介</option>
            <option value="owner">屋主</option>
          </select>
        </label>
        <label>目的
          <select value={intent} onChange={e => setIntent(e.target.value as any)} className="ml-1.5 rounded-[8px] border border-neutral-200 p-1.5">
            <option value="detail">詢問細節</option>
            <option value="view">預約看屋</option>
            <option value="pet">詢問寵物</option>
            <option value="price">試探價格</option>
          </select>
        </label>
      </div>
      <textarea
        rows={3}
        placeholder="隨便寫寫你想問的（例：這間多少錢？能不能養狗？）"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        className="w-full rounded-[8px] border border-neutral-200 p-2"
      />
      <button onClick={handleRewrite} disabled={loading} className="mt-2 rounded-[8px] border border-brand bg-brand px-3 py-2 text-white disabled:opacity-50">
        {loading ? "改寫中…" : "生成禮貌版本"}
      </button>
      {(v1 || v2) && (
        <div className="mt-2 grid gap-2">
          {v1 && (
            <div onClick={() => adopt(v1)} className="cursor-pointer rounded-[8px] border border-neutral-200 bg-neutral-50 p-2 hover:bg-neutral-100">
              <div className="mb-1 text-xs font-bold text-neutral-500">版本 A（較正式）</div>
              <div>{v1}</div>
            </div>
          )}
          {v2 && (
            <div onClick={() => adopt(v2)} className="cursor-pointer rounded-[8px] border border-neutral-200 bg-neutral-50 p-2 hover:bg-neutral-100">
              <div className="mb-1 text-xs font-bold text-neutral-500">版本 B（較親切）</div>
              <div>{v2}</div>
            </div>
          )}
        </div>
      )}
      {sent && <div className="mt-2 text-center text-sm text-green-600">已複製並填入！</div>}
    </div>
  );
};
