import { useState } from 'react'
import { Link } from 'react-router-dom'

type QuickAction = {
  label: string
  href: string
  iconPath: string
  primary?: boolean
}

type FilterPill =
  | {
      id: string
      label: string
      icon: string
      type: 'link'
      href: string
    }
  | {
      id: string
      label: string
      icon: string
      type: 'modal'
      modal: { title: string; body: string }
    }

const marqueeSegments: Array<{ type: 'text' | 'highlight'; value: string }> = [
  { type: 'text', value: '買房這麼大的事，先到 ' },
  { type: 'highlight', value: '邁鄰居' },
  { type: 'text', value: ' 為未來的家查口碑、找評價，最放心！' },
]

const quickActions: QuickAction[] = [
  {
    label: '房地產表列',
    href: '/maihouses/property.html',
    iconPath: 'M3 4h18v2H3V4zm0 7h18v2H3v-2zm0 7h18v2H3v-2z',
  },
  {
    label: '登入',
    href: '/auth.html?mode=login',
    iconPath:
      'M10 17l5-5-5-5v3H3v4h7v3zm9-12h-8v2h8v10h-8v2h8a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2z',
  },
  {
    label: '註冊',
    href: '/auth.html?mode=signup',
    iconPath: 'M12 12a5 5 0 1 0-5-5 5 5 0 0 0 5 5zm-9 9a9 9 0 0 1 18 0z',
    primary: true,
  },
]

const filterPills: FilterPill[] = [
  {
    id: 'community',
    label: '社區評價',
    icon: '●',
    type: 'link',
    href: '/maihouses/community-wall_mvp.html',
  },
  {
    id: 'agent',
    label: '房仲專區',
    icon: '●',
    type: 'modal',
    modal: { title: '房仲專區', body: '專業房仲服務與物件推薦' },
  },
  {
    id: 'neighbor',
    label: '邁鄰居',
    icon: '●',
    type: 'modal',
    modal: { title: '邁鄰居', body: '認識您的鄰居，建立社區連結' },
  },
]

export default function Header() {
  const [modalOpen, setModalOpen] = useState(false)
  const [modalContent, setModalContent] = useState({ title: '', body: '' })

  const openModal = (title: string, body: string) => {
    setModalContent({ title, body })
    setModalOpen(true)
  }

  return (
    <>
      <header className="sticky top-0 z-[1000] bg-white/95 backdrop-blur-[16px] border-b border-[#1a5fdb]/10 shadow-[0_4px_20px_rgba(26,95,219,0.06)] text-brand transition-all duration-300">
        <div className="mx-auto flex h-14 max-w-[1200px] items-center justify-between px-5 sm:h-[52px] sm:px-3">
          <div className="flex items-center gap-2.5 transition-all duration-300 hover:-translate-y-0.5 hover:scale-[1.02] sm:gap-2 cursor-pointer">
            <div className="relative h-[34px] w-[34px] overflow-hidden rounded-[10px] bg-gradient-to-br from-brand to-brand-light shadow-[0_4px_15px_rgba(26,95,219,0.3)] transition-all duration-400 before:absolute before:-left-1/2 before:-top-1/2 before:h-[200%] before:w-[200%] before:animate-[shine_2.5s_infinite] before:bg-gradient-to-br before:from-transparent before:via-white/40 before:to-transparent before:rotate-45 hover:scale-110 hover:rotate-[8deg] hover:shadow-[0_6px_20px_rgba(26,95,219,0.45),0_0_0_4px_rgba(106,164,255,0.3)] sm:h-7 sm:w-7" />
            <span className="relative text-[26px] font-black tracking-[1.5px] text-brand sm:text-[17px]">邁房子</span>
            <span className="relative ml-3 animate-[float_3s_ease-in-out_infinite] text-[15px] font-semibold italic text-neutral-500 opacity-85 md:hidden">讓家，不只是地址</span>
          </div>
          <div className="flex items-center gap-5 sm:gap-2">
            <nav className="flex items-center gap-2.5" aria-label="主要動作">
              {quickActions.map((action) => {
                const isStatic = action.href.includes('.html')
                const baseClass = "inline-flex min-h-[44px] items-center gap-2 rounded-[14px] border px-3.5 py-2.5 text-sm font-semibold backdrop-blur-[16px] transition-all duration-250 active:scale-95"
                const variantClass = action.primary 
                  ? "border-transparent bg-brand text-white shadow-[0_4px_14px_rgba(26,95,219,0.35)] hover:bg-brand-dark hover:shadow-[0_6px_20px_rgba(26,95,219,0.45)]"
                  : "border-[#0a2246]/10 bg-white/70 text-brand hover:bg-white/90 hover:shadow-sm"
                
                const className = `${baseClass} ${variantClass}`
                const content = (
                  <>
                    <svg className="mh-icon" viewBox="0 0 24 24" aria-hidden="true">
                      <path d={action.iconPath} />
                    </svg>
                    <span className="mh-label">{action.label}</span>
                  </>
                )

                if (isStatic) {
                  return (
                    <a key={action.label} className={className} href={action.href}>
                      {content}
                    </a>
                  )
                }

                return (
                  <Link key={action.label} className={className} to={action.href}>
                    {content}
                  </Link>
                )
              })}
            </nav>
          </div>
        </div>
      </header>

      {/* Panel 卡片 - 包含跑馬燈、搜索框、膠囊按鈕 */}
      <div className="panel">
        <div className="marquee-container" aria-live="polite">
          {marqueeSegments.map((segment, index) =>
            segment.type === 'highlight' ? (
              <b className="brand-highlight" key={segment.value + index}>
                {segment.value}
              </b>
            ) : (
              <span key={segment.value + index}>{segment.value}</span>
            )
          )}
        </div>

        <div className="search-container">
          {/* 主搜索框 */}
          <div className="search-box-modern">
            <label htmlFor="search-input" className="sr-only">
              搜尋框
            </label>
            <input
              type="text"
              id="search-input"
              name="search-query"
              className="search-input"
              placeholder="輸入社區名稱、地址或捷運站..."
              aria-label="搜尋框"
              onKeyDown={(e) => e.key === 'Enter' && console.log('Search triggered')}
            />
            <button className="search-btn-primary" onClick={() => console.log('Search triggered')}>
              搜索
            </button>
          </div>

          {/* 快速篩選膠囊按鈕 */}
          <div className="filter-pills">
            {filterPills.map((pill) => {
              if (pill.type === 'link') {
                return (
                  <a key={pill.id} href={pill.href} className="pill" style={{ textDecoration: 'none' }}>
                    <span className="pill-icon" aria-hidden="true">
                      {pill.icon}
                    </span>
                    {pill.label}
                  </a>
                )
              }

              return (
                <button
                  key={pill.id}
                  className="pill"
                  type="button"
                  onClick={() => openModal(pill.modal.title, pill.modal.body)}
                >
                  <span className="pill-icon" aria-hidden="true">
                    {pill.icon}
                  </span>
                  {pill.label}
                </button>
              )
            })}
          </div>
        </div>
      </div>

      {modalOpen && (
        <div className="modal-overlay" onClick={() => setModalOpen(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3>{modalContent.title}</h3>
              <button className="modal-close" onClick={() => setModalOpen(false)}>
                ×
              </button>
            </div>
            <div className="modal-body">
              <p>{modalContent.body}</p>
            </div>
          </div>
        </div>
      )}
    </>
  )
}
