import { useEffect, useRef, useState } from 'react'
import { Link } from 'react-router-dom'

type StepStatus = 'done' | 'active' | 'upcoming'

type AssureStep = {
  title: string
  subtitle: string
  status: StepStatus
}

const progressValue = 62

const assureSteps: AssureStep[] = [
  { title: '已看屋', subtitle: '完成現場帶看與基本紀錄', status: 'done' },
  { title: '已出價', subtitle: '要約與條件已留痕', status: 'done' },
  { title: '雙向簽署', subtitle: '平台簽署，雙方可回溯查驗', status: 'active' },
  { title: '身分驗證', subtitle: 'KYC 驗證與黑名單檢核', status: 'upcoming' },
  { title: '金流通知', subtitle: '代收代付與異常監控', status: 'upcoming' },
  { title: '交屋驗屋', subtitle: '交付清單與驗屋紀錄', status: 'upcoming' },
]

const assureChips = ['流程即時更新', '可疑變更自動警示']

export default function HeroAssure() {
  const [isVisible, setIsVisible] = useState(false)
  const cardRef = useRef<HTMLElement>(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry?.isIntersecting) {
          setIsVisible(true)
          observer.disconnect()
        }
      },
      { threshold: 0.1 }
    )

    if (cardRef.current) {
      observer.observe(cardRef.current)
    }

    return () => observer.disconnect()
  }, [])

  return (
    <section
      ref={cardRef}
      className="mx-auto max-w-[600px] overflow-hidden rounded-[28px] border border-[#e6edf7] bg-white shadow-[10px_10px_24px_rgba(9,15,30,0.16),-10px_-10px_24px_rgba(255,255,255,0.9)] transition-all duration-400"
      aria-label="安心保證流程"
      style={{
        opacity: isVisible ? 1 : 0,
        transform: isVisible ? 'translateY(0)' : 'translateY(20px)',
      }}
    >
      <header className="flex items-center justify-between gap-4 rounded-[16px] bg-gradient-to-br from-[#f0f5fa] to-[#e6f0ff] px-5 py-4">
        <div className="flex items-center gap-[14px]">
          <div className="grid h-9 w-9 place-items-center rounded-[10px] bg-gradient-to-br from-brand to-brand-light text-[18px] font-black text-white shadow-[0_6px_14px_rgba(0,78,124,0.25)]">🔒</div>
          <div>
            <h3 className="m-0 text-[clamp(17px,2.6vw,20px)] font-black leading-[1.28] text-brand">安心保證流程</h3>
            <div className="mt-[2px] text-[clamp(13px,1.6vw,14.5px)] leading-[1.28] text-[#6c7b91]">每一步都有紀錄與保障</div>
          </div>
        </div>
        <div className="flex items-center gap-0 before:content-['進度'] before:text-[11px] before:font-bold before:text-white before:tracking-[0.5px] before:bg-brand before:px-[10px] before:py-[6px] before:rounded-l-[12px] before:shadow-[0_2px_6px_rgba(0,78,124,0.15)]">
          <div className="relative flex items-baseline gap-[2px] rounded-r-[12px] border-[1.5px] border-l-0 border-brand bg-white py-[6px] pl-[10px] pr-[12px] shadow-[0_2px_6px_rgba(0,78,124,0.15)]" aria-label={`Progress: ${progressValue}%`}>
            <b className="text-[18px] font-black leading-none text-brand">{progressValue}</b>
            <span className="text-[11px] font-bold text-brand">%</span>
          </div>
        </div>
      </header>

      <div className="flex flex-col items-center gap-4 px-6 py-5">
        <div className="grid w-full max-w-[500px] gap-[14px] pl-[20px]">
          {assureSteps.map((step, index) => (
            <div
              className="grid grid-cols-[50px_1fr] items-start gap-[12px]"
              key={`${step.title}-${step.status}`}
            >
              <div className="relative flex h-full justify-center items-start">
                <div className={`relative z-[2] h-[18px] w-[18px] rounded-full border-[4px] ${
                  step.status === 'done' 
                    ? 'border-[#12b886] bg-gradient-to-br from-[#12b886] to-[#6be7c6] shadow-none' 
                    : step.status === 'active'
                      ? 'border-brand bg-white shadow-[0_0_0_8px_rgba(0,159,232,0.15),0_4px_10px_rgba(0,78,124,0.12)]'
                      : 'border-[#cfe1ff] bg-white shadow-[0_0_0_8px_rgba(0,159,232,0.15),0_4px_10px_rgba(0,78,124,0.12)]'
                }`}></div>
                {index < assureSteps.length - 1 && <div className="absolute bottom-[-14px] left-1/2 top-[20px] w-[2px] -translate-x-1/2 bg-gradient-to-b from-[#eaefff] to-[#d9e6ff]"></div>}
              </div>
              <div>
                <div className="text-[clamp(15px,2.0vw,17.5px)] font-extrabold leading-[1.28] text-[#0f1a39]">{step.title}</div>
                <div className="text-[clamp(13px,1.6vw,14.5px)] leading-[1.52] text-[#6c7b91]">{step.subtitle}</div>
              </div>
            </div>
          ))}
        </div>

        <div className="rounded-[12px] border border-dashed border-[#00385a] bg-[#f0f7ff] p-4 text-[13px] leading-[1.6] text-[#00385a] flex gap-3 items-start">
          <div className="flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-[#00385a] text-[10px] text-white">✔</div>
          <div>
            <b className="text-[#00385a]">你的權益：</b>完成<b>身分驗證</b>並開啟<b>金流通知</b>；所有簽署與溝通都在平台留痕，可回溯可查證。
            <div className="mt-3 flex flex-wrap gap-2">
              {assureChips.map((chip) => (
                <span 
                  key={chip} 
                  className="rounded-full border-[1.5px] border-[#00385a] bg-[rgba(0,56,90,0.08)] px-2.5 py-1 text-[11px] font-bold text-[#00385a] shadow-sm"
                >
                  {chip}
                </span>
              ))}
            </div>
          </div>
        </div>
      </div>

      <footer className="mt-4 flex items-center justify-between border-t border-[#e6edf7] px-6 pt-4 pb-5">
        <span className="text-[13px] font-medium text-[#6c7b91]">了解每一步保護了什麼</span>
        <Link to="/assure" className="rounded-full bg-[#f0f5fa] px-4 py-2 text-[13px] font-bold text-brand transition-colors hover:bg-[#e6f0ff]" aria-label="Read more about the protection details">
          詳讀保障內容
        </Link>
      </footer>
    </section>
  )
}
