import React, { useEffect, useMemo, useState } from "react";
import { getMilestoneHint, getWarmTags, ensureFirstSeen, isWarmbarDismissedToday, dismissWarmbarToday, loadProfile } from "../stores/profileStore";
import { Events, track } from "../analytics/track";

export const WarmWelcomeBar: React.FC = () => {
  const [shouldShow, setShouldShow] = useState(false);
  const profile = loadProfile();
  const tags = useMemo(() => getWarmTags(3), []);
  const milestone = useMemo(() => getMilestoneHint(profile.milestones), [profile.milestones]);

  useEffect(() => {
    const { isFirstVisit } = ensureFirstSeen();
    const hasContent = (tags && tags.length > 0) || !!milestone || !!profile.lastMood;
    const ok = !isFirstVisit && !isWarmbarDismissedToday() && hasContent;
    setShouldShow(ok);
  }, [tags, milestone, profile.lastMood]);

  const handleDismiss = () => {
    dismissWarmbarToday();
    setShouldShow(false);
    track(Events.WarmbarDismiss, {});
  };

  if (!shouldShow) return null;

  // 優先順序：心情 > 里程碑 > 標籤
  let content: React.ReactNode = null;
  if (profile.lastMood === "stress") {
    content = <span>看房辛苦了，今天放慢腳步，隨意看看就好 ☕</span>;
  } else if (milestone) {
    content = <span>{milestone}</span>;
  } else if (tags.length > 0) {
    content = <span>最近你似乎關注：{tags.join("、")}</span>;
  } else {
    return null;
  }

  return (
    <div className="flex h-[34px] w-full items-center justify-center gap-3 border-b border-[#E6ECFF] bg-[#F5F8FF] text-center text-sm leading-[34px] tracking-[0.3px] text-[#0a2246]">
      {content}
      <button onClick={handleDismiss} className="h-[26px] cursor-pointer rounded-full border border-[#C9D5FF] bg-white px-2.5 leading-[24px] text-brand">
        知道了
      </button>
    </div>
  );
};
